var oPopup = new function(){

	var obj = this;

	var opened = false;

	var elPopup = false;
	var elPopupIn, elPopupTitle, elPopupContent;

	/**
	 * @param	{string}	title
	 * @param	{string}	content
	 * @param	{boolean}	processForms
	 * @param	{boolean}	autoSize
	 */
	this.loadContent = function(title, content, processForms, autoSize){
		if(typeof(processForms) == 'undefined') processForms = true;
		if(typeof(autoSize) == 'undefined') autoSize = false;

		if(processForms){
			var forms = byTag('FORM', elPopupContent);
			for(var i = 0, l = forms.length; i < l; i++){
				addHandler(
					forms[i],
					'submit',
					function(e){
						AJAX.submitForm(
							e,
							this,
							function(newContent){
								obj.loadContent(title, newContent, true, autoSize);
							}
						);
						loading();
					}
				);
			}
		}

		if(!autoSize){
			$.fancybox.open(
				'<div>' + content + '</div>',
				{
					title: title,
					type			: 'inline',
					/*width			: '100%',
					 height			: '100%',*/
					height			: 'auto',
					//minHeight		: '650px',
					autoSize		: false,
					padding			: 20,
					tpl				: {
						closeBtn : '<a title="Close" class="fancybox-item fancybox-close" href="javascript:;"><span class="icon text-red-600 hover:text-red-800 !text-5xl leading-none no-underline hover:no-underline -mt-12">Г—</span></a>'
					},
					helpers			: {
						title : {
							type : 'inside',
							position : 'top'
						}
					}
				}
			);
		}else{
			$.fancybox.open(
				'<div>' + content + '</div>',
				{
					title: title,
					type			: 'inline',
					/*width			: '100%',
					 height			: '100%',*/
					minWidth		: '250px',
					height			: 'auto',
					//minHeight		: '650px',
					autoSize		: true,
					padding			: 20,
					tpl				: {
						closeBtn : '<a title="Close" class="fancybox-item fancybox-close" href="javascript:;"><span class="icon text-red-600 hover:text-red-800 !text-5xl leading-none no-underline hover:no-underline -mt-12">Г—</span></a>'
					},
					helpers			: {
						title : {
							type : 'inside',
							position : 'top'
						}
					}
				}
			);
		}
	};


	/**
	 * @param	{string}	title
	 * @param	{string}	url
	 * @param	{boolean}	processForms
	 * @param	{boolean}	autoSize
	 * @param	{function}	callback
	 */
	this.loadUrl = function(title, url, processForms, callback, autoSize){

		loading();
		AJAX.lookup(
			url,
			function(content){
				obj.loadContent(title, content, processForms, autoSize);
				if(typeof(callback) == 'function'){
					callback();
				}
				RSGoPro_InitMaskPhone();
			}
		);
	};


	/**
	 *
	 */
	function loading(){
		$.fancybox.showLoading();
	}
};
var oItemsScroll, oItemsTabs;

oItemsScroll = new function(){
	var scrollStep = 20;
	var scrollStepsOneTime = 20;
	var scrollMax = 0;
	var menuStartPos = 0;
	var pointsIds = [];
	var points = [];
	var inited = false;
	var obj = this;
	var posDecrease = 70;

	function init(){
		scrollMax = D.body.scrollHeight ? D.body.scrollHeight : D.documentElement.scrollHeight;
		scrollMax -= winSize().h;

		var itemsBlock = $$$('groups-tabs');
		if(!itemsBlock || !$$$('groups-menu')) return;

		menuStartPos = elPos($$$('series-items-title')).y - 80;

		if($$$('groups-menu').offsetHeight > 50) {
			posDecrease = 100;
		}else{
			posDecrease = 70;
		}
		//console.log(posDecrease);

		if(!inited){
			var aTags = byTag('A', itemsBlock);
			pointsIds = [];
			for(var i = 0, l = aTags.length; i < l; i++){
				if(aTags[i].className.indexOf('items-scroll-point') !== -1){
					pointsIds.push(aTags[i].id);
					points[aTags[i].id] = elPos(aTags[i]).y;
				}
			}

			var urlNow = D.location.href;
			for(i = 0, l = pointsIds.length; i < l; i++){
				removeElement($$$(pointsIds[i]));
			}
			if(D.location.href.indexOf('#items-list') !== -1){
				setTimeout(
					function(){
						obj.navTo('#' + pointsIds[0]);
					},
					200
				);
			}

			setInterval(
				function(){
					for(var i = 0; i < scrollStepsOneTime; i++){
						scroll();
					}
				},
				10
			);
			addHandler(window, 'scroll', function(e){onScroll()});
			onScroll();
		}
		inited = true;
	}
	addHandler(window, 'load', function(){
		init();
	});
	addHandler(window, 'resize', function(){
		init();
	});

	this.navTo = function(anchorUrl){
		var pid = anchorUrl.split('#')[1];
		if(typeof(points[pid]) == 'undefined') return true;

		scrollTo(points[pid] - posDecrease);
		return false;
	};


	var scrollTarget = -1;

	function scrollTo(s){
		if(s > scrollMax){
			s = scrollMax;
		}
		if(s < 0){
			s = 0;
		}
		scrollTarget = s;
	}


	function scroll(){
		if(scrollTarget == -1) return;

		var scrollNow = D.body.scrollTop ? D.body.scrollTop : D.documentElement.scrollTop;

		var dir = scrollTarget > scrollNow ? 1 : -1;
		var scrollNew = scrollNow + scrollStep * dir;
		if(Math.abs(scrollNew - scrollTarget) < scrollStep){
			scrollNew = scrollTarget;
			scrollTarget = -1;
			onScroll();
			if($$$('groups-menu').className.indexOf(' floating') !== -1 && $$$('groups-menu').offsetHeight > 40){
				scrollNew -= 50;
			}
		}

		D.body.scrollTop = scrollNew;
		D.documentElement.scrollTop = scrollNew;

		onScroll();
	}


	//var changeUrlTimeout = false;

	function onScroll() {
		var scrollPos = D.body.scrollTop ? D.body.scrollTop : D.documentElement.scrollTop;
		// new code
		var topMenuHeight = document.querySelector('#tpanel .tpanel_inner').offsetHeight;
		// Р’РєР»СЋС‡Р°РµРј/РІС‹РєР»СЋС‡Р°РµРј "РїР»Р°РІР°РЅРёРµ" РґР»СЏ РјРµРЅСЋ РіСЂСѓРїРї С‚РѕРІР°СЂРѕРІ
		if (scrollPos >= menuStartPos) {
			if ($$$('groups-menu').className.indexOf(' floating') === -1) {
				$$$('groups-menu').className += ' floating';
				// new code
				$$$('groups-menu').style.top = topMenuHeight + 'px';
			}
		} else {
			$$$('groups-menu').className = $$$('groups-menu').className.replace(' floating', '');
			// new code
			$$$('groups-menu').style.top = '0px';
		}

		// РћРїСЂРµРґРµР»СЏРµРј, РІ РѕР±Р»Р°СЃС‚Рё РєР°РєРѕР№ РіСЂСѓРїРїС‹ С‚РѕРІР°СЂРѕРІ РјС‹ СЃРµР№С‡Р°СЃ РЅР°С…РѕРґРёРјСЃСЏ
		//var urlNew = '#';
		var pActive = pointsIds[0];
		for(var i = 0, l = pointsIds.length; i < l; i++){
			if(scrollPos >= (points[pointsIds[i]] - 300)){
				pActive = pointsIds[i];
				//urlNew = '#' + pActive;
			}
		}
		if(scrollPos >= scrollMax - 200){
			pActive = pointsIds[pointsIds.length-1];
		}

		// РџРѕСЃРІРµС‡РёРІР°РµРј РїСѓРЅРєС‚ РјРµРЅСЋ
		for(i = 0, l = pointsIds.length; i < l; i++){
			$$$('menu-' + pointsIds[i]).className = '';
		}
		$$$('menu-' + pActive).className = 'active';
	}
};
